"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["57587"],{75628(s){s.exports=JSON.parse('{"tag":{"label":"analysis","permalink":"/sysanalyst-kb.github.io/docs/tags/analysis","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":5,"items":[{"id":"process/cost-benefit-analysis","title":"Cost-Benefit Analysis (CBA)","description":"Cost-Benefit Analysis \u2014 \u043C\u0435\u0442\u043E\u0434 \u0441\u0440\u0430\u0432\u043D\u0435\u043D\u0438\u044F \u0437\u0430\u0442\u0440\u0430\u0442 \u043D\u0430 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044E \u0440\u0435\u0448\u0435\u043D\u0438\u044F \u0441 \u0432\u044B\u0433\u043E\u0434\u0430\u043C\u0438 \u043E\u0442 \u0435\u0433\u043E \u0432\u043D\u0435\u0434\u0440\u0435\u043D\u0438\u044F. \u041F\u043E\u0437\u0432\u043E\u043B\u044F\u0435\u0442 \u043E\u0442\u0432\u0435\u0442\u0438\u0442\u044C \u043D\u0430 \u0432\u043E\u043F\u0440\u043E\u0441: \u0441\u0442\u043E\u0438\u0442 \u043B\u0438 \u044D\u0442\u043E \u0434\u0435\u043B\u0430\u0442\u044C?","permalink":"/sysanalyst-kb.github.io/docs/process/cost-benefit-analysis"},{"id":"specialization/ai-ml-eda","title":"EDA \u2014 \u0440\u0430\u0437\u0432\u0435\u0434\u043E\u0447\u043D\u044B\u0439 \u0430\u043D\u0430\u043B\u0438\u0437 \u0434\u0430\u043D\u043D\u044B\u0445 \u0434\u043B\u044F ML","description":"EDA (Exploratory Data Analysis) \u2014 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u0434\u0430\u043D\u043D\u044B\u0445 \u043F\u0435\u0440\u0435\u0434 \u043F\u043E\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u0435\u043C ML-\u043C\u043E\u0434\u0435\u043B\u0438: \u043F\u043E\u0438\u0441\u043A \u0437\u0430\u043A\u043E\u043D\u043E\u043C\u0435\u0440\u043D\u043E\u0441\u0442\u0435\u0439, \u0432\u044B\u0431\u0440\u043E\u0441\u043E\u0432, \u043F\u0440\u043E\u043F\u0443\u0441\u043A\u043E\u0432, \u043F\u0440\u043E\u0432\u0435\u0440\u043A\u0430 \u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u0438\u0439. AI-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442 EDA, \u0447\u0442\u043E\u0431\u044B \u043E\u0446\u0435\u043D\u0438\u0442\u044C, \u043F\u0440\u0438\u0433\u043E\u0434\u043D\u044B \u043B\u0438 \u0434\u0430\u043D\u043D\u044B\u0435 \u0434\u043B\u044F ML, \u0438 \u0441\u0444\u043E\u0440\u043C\u0443\u043B\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F \u043A \u0438\u0445 \u043E\u0447\u0438\u0441\u0442\u043A\u0435.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ai-ml-eda"},{"id":"process/stakeholder-analysis","title":"\u0410\u043D\u0430\u043B\u0438\u0437 \u0441\u0442\u0435\u0439\u043A\u0445\u043E\u043B\u0434\u0435\u0440\u043E\u0432 (Power/Interest Grid)","description":"\u0421\u0442\u0435\u0439\u043A\u0445\u043E\u043B\u0434\u0435\u0440\u044B \u2014 \u044D\u0442\u043E \u043B\u044E\u0434\u0438 \u0438 \u0433\u0440\u0443\u043F\u043F\u044B, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432\u043B\u0438\u044F\u044E\u0442 \u043D\u0430 \u043F\u0440\u043E\u0435\u043A\u0442 \u0438\u043B\u0438 \u0437\u0430\u0432\u0438\u0441\u044F\u0442 \u043E\u0442 \u0435\u0433\u043E \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u043E\u0432. \u0417\u0430\u0434\u0430\u0447\u0430 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430 \u2014 \u043F\u043E\u043D\u044F\u0442\u044C, \u043A\u0442\u043E \u043D\u0430 \u0447\u0442\u043E \u0432\u043B\u0438\u044F\u0435\u0442, \u0438 \u0432\u044B\u0441\u0442\u0440\u043E\u0438\u0442\u044C \u043A\u043E\u043C\u043C\u0443\u043D\u0438\u043A\u0430\u0446\u0438\u044E \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E.","permalink":"/sysanalyst-kb.github.io/docs/process/stakeholder-analysis"},{"id":"specialization/medtech-lis","title":"\u041B\u0418\u0421 \u2014 \u043B\u0430\u0431\u043E\u0440\u0430\u0442\u043E\u0440\u043D\u044B\u0435 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B","description":"\u041B\u0418\u0421 (\u043B\u0430\u0431\u043E\u0440\u0430\u0442\u043E\u0440\u043D\u0430\u044F \u0418\u0421) \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u0442 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u043E\u043C \u0430\u043D\u0430\u043B\u0438\u0437\u0430 \u0431\u0438\u043E\u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u043E\u0432 \u0448\u0442\u0440\u0438\u0445\u043A\u043E\u0434\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u043F\u0440\u043E\u0431\u0438\u0440\u043E\u043A, \u0430\u0432\u0442\u043E\u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F (70%+ \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u043E\u0432 \u0431\u0435\u0437 \u0443\u0447\u0430\u0441\u0442\u0438\u044F \u043B\u0430\u0431\u043E\u0440\u0430\u043D\u0442\u0430), \u0440\u0435\u0444\u0435\u0440\u0435\u043D\u0441\u043D\u044B\u0435 \u0438\u043D\u0442\u0435\u0440\u0432\u0430\u043B\u044B \u0438 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044F \u0441 \u043B\u0430\u0431\u043E\u0440\u0430\u0442\u043E\u0440\u043D\u044B\u043C\u0438 \u0430\u043D\u0430\u043B\u0438\u0437\u0430\u0442\u043E\u0440\u0430\u043C\u0438. \u0412 \u0442\u0438\u043F\u043E\u0432\u043E\u0439 \u043B\u0430\u0431\u043E\u0440\u0430\u0442\u043E\u0440\u0438\u0438 \u2014 10 000+ \u043F\u0440\u043E\u0431/\u0434\u0435\u043D\u044C, \u0434\u043E 500 \u0432\u0438\u0434\u043E\u0432 \u0430\u043D\u0430\u043B\u0438\u0437\u043E\u0432.","permalink":"/sysanalyst-kb.github.io/docs/specialization/medtech-lis"},{"id":"process/risk-management","title":"\u0423\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0440\u0438\u0441\u043A\u0430\u043C\u0438","description":"\u0420\u0438\u0441\u043A \u2014 \u044D\u0442\u043E \u0441\u043E\u0431\u044B\u0442\u0438\u0435, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043C\u043E\u0436\u0435\u0442 \u043F\u0440\u043E\u0438\u0437\u043E\u0439\u0442\u0438 \u0438 \u043F\u043E\u0432\u043B\u0438\u044F\u0442\u044C \u043D\u0430 \u043F\u0440\u043E\u0435\u043A\u0442 (\u043F\u043E\u043B\u043E\u0436\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0438\u043B\u0438 \u043E\u0442\u0440\u0438\u0446\u0430\u0442\u0435\u043B\u044C\u043D\u043E). \u0423\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0440\u0438\u0441\u043A\u0430\u043C\u0438 \u2014 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u0438\u0434\u0435\u043D\u0442\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438, \u0430\u043D\u0430\u043B\u0438\u0437\u0430, \u043F\u043B\u0430\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0440\u0435\u0430\u043A\u0446\u0438\u0438 \u0438 \u043C\u043E\u043D\u0438\u0442\u043E\u0440\u0438\u043D\u0433\u0430 \u0440\u0438\u0441\u043A\u043E\u0432.","permalink":"/sysanalyst-kb.github.io/docs/process/risk-management"}],"unlisted":false}}')}}]);